class Solution:
    def findDuplicate(self, paths: List[str]) -> List[List[str]]:
        content_map = {}
        for path in paths:
            dir_path, *files = path.split()
            for file in files:
                file_name, content = file.split('(')
                content = content[:-1]
                if content not in content_map:
                    content_map[content] = []
                content_map[content].append(f"{dir_path}/{file_name}")
        return [file_paths for file_paths in content_map.values() if len(file_paths) > 1]
